def causal_mask(T):
    """
    Returns a T x T mask where mask[i][j] = 0 if j <= i (allowed)
    and mask[i][j] = -inf if j > i (masked future).
    Used by adding to attention scores before softmax.
    """
    NEG_INF = float('-inf')
    return [
        [0.0 if j <= i else ___________  for j in range(T)]
        for i in range(T)
    ]

def apply_causal_mask(scores, mask):
    """Add mask to score matrix elementwise."""
    return [
        [scores[i][j] + mask[i][j] for j in range(len(scores[i]))]
        for i in range(len(scores))
    ]
